void ZopfliLZ77Optimal(ZopfliBlockState *s,
                       const unsigned char *in, size_t instart, size_t inend,
                       int numiterations,
                       ZopfliLZ77Store *store)
{
    /* Dist to get to here with smallest cost. */
    size_t blocksize = inend - instart;
    unsigned short *length_array =
        (unsigned short *)malloc(sizeof(unsigned short) * (blocksize + 1));
    unsigned short *path = 0;
    size_t pathsize = 0;
    ZopfliLZ77Store currentstore;
    ZopfliHash hash;
    ZopfliHash *h = &hash;
    SymbolStats stats, beststats, laststats;
    int i;
    float *costs = (float *)malloc(sizeof(float) * (blocksize + 1));
    double cost;
    double bestcost = ZOPFLI_LARGE_FLOAT;
    double lastcost = 0;
    /* Try randomizing the costs a bit once the size stabilizes. */
    RanState ran_state;
    int lastrandomstep = -1;

    if (!costs)
        exit(-1); /* Allocation failed. */
    if (!length_array)
        exit(-1); /* Allocation failed. */

    InitRanState(&ran_state);
    InitStats(&stats);
    ZopfliInitLZ77Store(in, &currentstore);
    ZopfliAllocHash(ZOPFLI_WINDOW_SIZE, h);

    /* Do regular deflate, then loop multiple shortest path runs, each time using
    the statistics of the previous run. */

    /* Initial run. */
    ZopfliLZ77Greedy(s, in, instart, inend, &currentstore, h);
    GetStatistics(&currentstore, &stats);

    /* Repeat statistics with each time the cost model from the previous stat
    run. */
    for (i = 0; i < numiterations; i++)
    {
        ZopfliCleanLZ77Store(&currentstore);
        ZopfliInitLZ77Store(in, &currentstore);
        LZ77OptimalRun(s, in, instart, inend, &path, &pathsize,
                       length_array, GetCostStat, (void *)&stats,
                       &currentstore, h, costs);
        cost = ZopfliCalculateBlockSize(&currentstore, 0, currentstore.size, 2);
        if (s->options->verbose_more || (s->options->verbose && cost < bestcost))
        {
            fprintf(stderr, "Iteration %d: %d bit\n", i, (int)cost);
        }
        if (cost < bestcost)
        {
            /* Copy to the output store. */
            ZopfliCopyLZ77Store(&currentstore, store);
            CopyStats(&stats, &beststats);
            bestcost = cost;
        }
        CopyStats(&stats, &laststats);
        ClearStatFreqs(&stats);
        GetStatistics(&currentstore, &stats);
        if (lastrandomstep != -1)
        {
            /* This makes it converge slower but better. Do it only once the
            randomness kicks in so that if the user does few iterations, it gives a
            better result sooner. */
            AddWeighedStatFreqs(&stats, 1.0, &laststats, 0.5, &stats);
            CalculateStatistics(&stats);
        }
        if (i > 5 && cost == lastcost)
        {
            CopyStats(&beststats, &stats);
            RandomizeStatFreqs(&ran_state, &stats);
            CalculateStatistics(&stats);
            lastrandomstep = i;
        }
        lastcost = cost;
    }

    free(length_array);
    free(path);
    free(costs);
    ZopfliCleanLZ77Store(&currentstore);
    ZopfliCleanHash(h);
}

/*
Finds next block to try to split, the largest of the available ones.
The largest is chosen to make sure that if only a limited amount of blocks is
requested, their sizes are spread evenly.
lz77size: the size of the LL77 data, which is the size of the done array here.
done: array indicating which blocks starting at that position are no longer
splittable (splitting them increases rather than decreases cost).
splitpoints: the splitpoints found so far.
npoints: the amount of splitpoints found so far.
lstart: output variable, giving start of block.
lend: output variable, giving end of block.
returns 1 if a block was found, 0 if no block found (all are done).
*/
/* Specification helpers for FindLargestSplittableBlock.
 *
 * We pin npoints to 2, giving three candidate blocks (i = 0,1,2):
 *   B0: start = 0,      end = splitpoints[0]
 *   B1: start = sp[0],  end = splitpoints[1]
 *   B2: start = sp[1],  end = lz77size - 1
 * Pinning npoints lets the loop fully unwind and lets us write an exact-value
 * postcondition.  Three blocks (rather than two) are needed so that the middle
 * block B1 has start > 0: only then does the `longest = end - start` update
 * feed a later comparison, which is what makes the `end + start` mutant on that
 * assignment observable.
 *
 * The selection is a running maximum over the *valid* blocks (done[start]==0)
 * with a strict `>` test seeded at 0, so a block is chosen only if its size is
 * strictly greater than every earlier chosen size (earliest wins ties) and a
 * size-0 block is never chosen. */
#define FLSB_S0   (splitpoints[0])

