/* InitStats zeroes all four stat tables.  is_fresh guarantees stats is a
   fully-allocated SymbolStats object so the memset's are in-bounds.  Each
   ensures pins one destination table element-for-element to 0. */
static void InitStats(SymbolStats *stats)
__CPROVER_requires(__CPROVER_is_fresh(stats, sizeof(*stats)))
__CPROVER_assigns(__CPROVER_object_whole(stats))
__CPROVER_ensures(__CPROVER_forall {
    int k1; (0 <= k1 && k1 < ZOPFLI_NUM_LL) ==> stats->litlens[k1] == 0 })
__CPROVER_ensures(__CPROVER_forall {
    int k2; (0 <= k2 && k2 < ZOPFLI_NUM_D) ==> stats->dists[k2] == 0 })
__CPROVER_ensures(__CPROVER_forall {
    int k3; (0 <= k3 && k3 < ZOPFLI_NUM_LL) ==> stats->ll_symbols[k3] == 0 })
__CPROVER_ensures(__CPROVER_forall {
    int k4; (0 <= k4 && k4 < ZOPFLI_NUM_D) ==> stats->d_symbols[k4] == 0 })
{
    memset(stats->litlens, 0, ZOPFLI_NUM_LL * sizeof(stats->litlens[0]));
    memset(stats->dists, 0, ZOPFLI_NUM_D * sizeof(stats->dists[0]));

    memset(stats->ll_symbols, 0, ZOPFLI_NUM_LL * sizeof(stats->ll_symbols[0]));
    memset(stats->d_symbols, 0, ZOPFLI_NUM_D * sizeof(stats->d_symbols[0]));
}

