static double LZ77OptimalRun(ZopfliBlockState *s,
                             const unsigned char *in, size_t instart, size_t inend,
                             unsigned short **path, size_t *pathsize,
                             unsigned short *length_array, CostModelFun *costmodel,
                             void *costcontext, ZopfliLZ77Store *store,
                             ZopfliHash *h, float *costs)
__CPROVER_requires(costmodel != NULL)
__CPROVER_requires(instart <= inend)
__CPROVER_requires(h != NULL)
__CPROVER_requires(__CPROVER_OBJECT_SIZE(length_array) == sizeof(unsigned short) * (inend - instart + 1))
__CPROVER_requires(__CPROVER_OBJECT_SIZE(costs) == sizeof(float) * (inend - instart + 1))
__CPROVER_ensures(instart == inend ==> __CPROVER_return_value == 0)
{
    double cost = GetBestLengths(s, in, instart, inend, costmodel,
                                 costcontext, length_array, h, costs);
    free(*path);
    *path = 0;
    *pathsize = 0;
    TraceBackwards(inend - instart, length_array, path, pathsize);
    FollowPath(s, in, instart, inend, *path, *pathsize, store, h);
    assert(cost < ZOPFLI_LARGE_FLOAT);
    return cost;
}

void ZopfliCleanHash(ZopfliHash *h)
__CPROVER_requires(__CPROVER_is_fresh(h, sizeof(*h)))
__CPROVER_requires(__CPROVER_is_fresh(h->head, sizeof(*h->head)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev, sizeof(*h->prev)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval, sizeof(*h->hashval)))
__CPROVER_requires(__CPROVER_is_fresh(h->head2, sizeof(*h->head2)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev2, sizeof(*h->prev2)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval2, sizeof(*h->hashval2)))
__CPROVER_requires(__CPROVER_is_fresh(h->same, sizeof(*h->same)))
__CPROVER_assigns(__CPROVER_object_whole(h->head), __CPROVER_object_whole(h->prev), __CPROVER_object_whole(h->hashval), __CPROVER_object_whole(h->head2), __CPROVER_object_whole(h->prev2), __CPROVER_object_whole(h->hashval2), __CPROVER_object_whole(h->same))
__CPROVER_frees(h->head, h->prev, h->hashval, h->head2, h->prev2, h->hashval2, h->same)
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->head)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->prev)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->hashval)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->head2)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->prev2)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->hashval2)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->same)))
{
    free(h->head);
    free(h->prev);
    free(h->hashval);

    free(h->head2);
    free(h->prev2);
    free(h->hashval2);

    free(h->same);
}

void ZopfliAllocHash(size_t window_size, ZopfliHash *h)
__CPROVER_requires(window_size > 0)
__CPROVER_requires(window_size <= __CPROVER_max_malloc_size / sizeof(int))
__CPROVER_requires(__CPROVER_is_fresh(h, sizeof(*h)))
__CPROVER_assigns(__CPROVER_object_whole(h))
__CPROVER_ensures(__CPROVER_is_fresh(h->head, sizeof(int) * 65536))

   live, distinct objects.  The greedy parse walks the input once, so instart
   never exceeds inend, and the input is readable over [0, inend) (it is indexed
   directly as in[i] and in[i - 1] when emitting literals). */
__CPROVER_requires(__CPROVER_is_fresh(s, sizeof(*s)))
__CPROVER_requires(__CPROVER_is_fresh(h, sizeof(*h)))
__CPROVER_requires(__CPROVER_is_fresh(h->head, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(h->same, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(h->head2, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev2, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval2, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(store, sizeof(*store)))
__CPROVER_requires(__CPROVER_is_fresh(store->litlens, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->dists, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->pos, sizeof(size_t)))
__CPROVER_requires(__CPROVER_is_fresh(store->ll_symbol, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->d_symbol, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->ll_counts, sizeof(size_t)))
__CPROVER_requires(__CPROVER_is_fresh(store->d_counts, sizeof(size_t)))
__CPROVER_requires(instart <= inend)
__CPROVER_requires(__CPROVER_is_fresh(in, inend * sizeof(*in)))
/* Frame: the parse mutates only the rolling-hash state (via the hash callees)
   and the output store (via ZopfliStoreLitLenDist).  Both are given as whole
   objects since the exact slots touched depend on the data-driven trip count. */
__CPROVER_assigns(h->val, h->val2,
                  __CPROVER_object_whole(h->head), __CPROVER_object_whole(h->prev),
                  __CPROVER_object_whole(h->hashval), __CPROVER_object_whole(h->same),
                  __CPROVER_object_whole(h->head2), __CPROVER_object_whole(h->prev2),
                  __CPROVER_object_whole(h->hashval2))
__CPROVER_assigns(store->size,
                  __CPROVER_object_whole(store->litlens), __CPROVER_object_whole(store->dists),
                  __CPROVER_object_whole(store->pos), __CPROVER_object_whole(store->ll_symbol),
                  __CPROVER_object_whole(store->d_symbol), __CPROVER_object_whole(store->ll_counts),
                  __CPROVER_object_whole(store->d_counts))
{
    size_t i = 0, j;
    unsigned short leng;
    unsigned short dist;
